<script setup lang="ts">import{computed}from'vue';import{LayoutDashboard,BookOpen,Users,ChartNoAxesColumnIncreasing,Plug,Settings,GraduationCap}from'lucide-vue-next';import{useAuthStore}from'@/stores/auth';import{useUiStore}from'@/stores/ui';const auth=useAuthStore(),ui=useUiStore();const items=[['/app',LayoutDashboard,'Обзор'],['/app/courses',BookOpen,'Курсы'],['/app/learners',Users,'Ученики'],['/app/analytics',ChartNoAxesColumnIncreasing,'Аналитика'],['/app/integrations',Plug,'Интеграции']];const name=computed(()=>String(auth.user?.user_metadata?.display_name??auth.user?.email??'Пользователь'));const initials=computed(()=>name.value.split(/[ @]/).filter(Boolean).slice(0,2).map(x=>x[0]?.toUpperCase()).join(''))</script><template><div v-if="ui.sidebarOpen" class="sidebar-overlay" @click="ui.sidebarOpen=false"></div><aside :class="['sidebar',ui.sidebarOpen&&'is-open']"><div class="brand"><span class="brand-mark"><GraduationCap :size="22"/></span><strong>Курсор</strong></div><nav><RouterLink v-for="[to,icon,label] in items" :key="to as string" :to="to as string" @click="ui.sidebarOpen=false"><component :is="icon" :size="19"/>{{label}}</RouterLink></nav><div class="sidebar-bottom"><RouterLink to="/app/settings" @click="ui.sidebarOpen=false"><Settings :size="19"/>Настройки</RouterLink><div class="profile"><span>{{initials}}</span><div><b>{{name}}</b><small>{{auth.organization?.role??'Участник'}}</small></div></div></div></aside></template>